        function enterGallery() {
            document.getElementById('landingPage').style.display = 'none';
            document.getElementById('galleryPage').classList.add('active');
            displayBooks();
        }

        function backToLanding() {
            document.getElementById('galleryPage').classList.remove('active');
            document.getElementById('landingPage').style.display = 'flex';
        }

        function displayBooks() {
            const container = document.getElementById('booksContainer');
            container.innerHTML = '';

            storybooks.forEach(book => {
                const bookCard = document.createElement('div');
                bookCard.className = 'book-card';
                bookCard.onclick = () => openModal(book);

                bookCard.innerHTML = `
                    <div class="book-front">
                        <img src="${book.cover}" alt="${book.title}" class="book-cover">
                        <div class="book-info">
                            <h3 class="book-title">${book.title}</h3>
                            <p class="book-author">by ${book.author}</p>
                        </div>
                    </div>
                `;

                container.appendChild(bookCard);
            });
        }

        function openModal(book) {
            currentBookIndex = storybooks.findIndex(b => b.id === book.id);
            currentPageIndex = 0;
            displayBookInModal();
            document.getElementById('modal').classList.add('active');
        }

        function displayBookInModal() {
            const book = storybooks[currentBookIndex];
            const page = book.pages[currentPageIndex];
            const modalBody = document.getElementById('modalBody');

            // Calculate sequential page numbers without repeats
            const leftPageNum = currentPageIndex * 2 + 1;
            const rightPageNum = currentPageIndex * 2 + 2;

            let leftContent = '';
            if (page.leftContent === 'cover') {
                leftContent = `
                    <img src="${book.cover}" alt="${book.title}" class="book-cover-modal">
                    <h3 style="color: #8b6f4e; margin-bottom: 15px; font-size: 2em; text-align: center; font-family: 'Georgia', serif;">${book.title}</h3>
                    <p style="text-align: center; font-style: italic; margin-bottom: 25px; font-size: 1.1em; color: #6b5d54;">by ${book.author}</p>
                    <div style="margin-top: 25px; line-height: 2; padding: 20px; background: rgba(139, 111, 78, 0.05); border-radius: 8px;">
                        <p style="margin-bottom: 12px;"><strong style="color: #8b6f4e;">Genre:</strong> <span style="color: #6b5d54;">${book.genre}</span></p>
                    </div>
                `;
            } else {
                leftContent = `<div style="line-height: 2; text-align: justify; font-size: 1.05em; color: #5a4a42; white-space: pre-line; padding: 20px;">${page.leftContent}</div>`;
            }

            let rightContent = '';
            if (page.rightContent === 'synopsis') {
                rightContent = `
                    <h4 style="color: #8b6f4e; margin-bottom: 25px; font-size: 1.6em; border-bottom: 2px solid #8b6f4e; padding-bottom: 12px; font-family: 'Georgia', serif;">Synopsis</h4>
                    <p style="line-height: 2.2; text-align: justify; text-indent: 40px; font-size: 1.08em; color: #5a4a42; letter-spacing: 0.3px; margin-bottom: 30px;">${book.excerpt}</p>
                `;
            } else {
                rightContent = `<div style="line-height: 2; text-align: justify; font-size: 1.05em; color: #5a4a42; white-space: pre-line; padding: 35px;">${page.rightContent}</div>`;
            }

            modalBody.innerHTML = `
                <div class="book-container">
                    <div class="nav-arrow prev-arrow ${currentPageIndex === 0 ? 'disabled' : ''}" onclick="previousPage()">
                        ‹
                    </div>
                    <div class="book-layout" id="bookLayout">
                        <div class="book-page book-left-page">
                            <div class="book-spine"></div>
                            ${leftContent}
                            <div class="page-number">${leftPageNum}</div>
                        </div>
                        <div class="book-page book-right-page">
                            ${rightContent}
                            <div class="page-number">${rightPageNum}</div>
                        </div>
                    </div>
                    <div class="nav-arrow next-arrow ${currentPageIndex === book.pages.length - 1 ? 'disabled' : ''}" onclick="nextPage()">
                        ›
                    </div>
                </div>
                <div class="book-indicator">Book ${currentBookIndex + 1} of ${storybooks.length} - Spread ${currentPageIndex + 1} of ${book.pages.length}</div>
            `;
        }

        function previousBook() {
            if (currentBookIndex > 0) {
                const bookLayout = document.getElementById('bookLayout');
                bookLayout.classList.add('page-turn-left');
                
                setTimeout(() => {
                    currentBookIndex--;
                    displayBookInModal();
                }, 300);
            }
        }

        function nextBook() {
            if (currentBookIndex < storybooks.length - 1) {
                const bookLayout = document.getElementById('bookLayout');
                bookLayout.classList.add('page-turn-right');
                
                setTimeout(() => {
                    currentBookIndex++;
                    displayBookInModal();
                }, 300);
            }
        }

        function previousPage() {
            if (currentPageIndex > 0) {
                currentPageIndex--;
                displayBookInModal();
            }
        }

        function nextPage() {
            const book = storybooks[currentBookIndex];
            if (currentPageIndex < book.pages.length - 1) {
                currentPageIndex++;
                displayBookInModal();
            }
        }

        function closeModal() {
            document.getElementById('modal').classList.remove('active');
        }

        function toggleTheme() {
            document.body.classList.toggle('dark-mode');
            const btn = document.querySelector('.theme-toggle');
            btn.textContent = document.body.classList.contains('dark-mode') ? '☀️' : '🌙';

            // Save theme preference to localStorage
            const isDarkMode = document.body.classList.contains('dark-mode');
            localStorage.setItem('theme', isDarkMode ? 'dark' : 'light');
        }

        // Load theme preference on page load
        document.addEventListener('DOMContentLoaded', function() {
            const savedTheme = localStorage.getItem('theme');
            if (savedTheme === 'dark') {
                document.body.classList.add('dark-mode');
                const btn = document.querySelector('.theme-toggle');
                if (btn) btn.textContent = '☀️';
            }
        });

        window.onclick = function(event) {
            const modal = document.getElementById('modal');
            if (event.target === modal) {
                closeModal();
            }
        }

        // Keyboard navigation
        document.addEventListener('keydown', function(event) {
            const modal = document.getElementById('modal');
            if (modal.classList.contains('active')) {
                if (event.key === 'ArrowLeft') {
                    previousBook();
                } else if (event.key === 'ArrowRight') {
                    nextBook();
                } else if (event.key === 'Escape') {
                    closeModal();
                }
            }
        });

        
